head.b:skin:
/* Variable Definitions */
:root {
    --primary: #e74c3c;
    --sidebar-bg: rgba(255, 255, 255, 0.8);
    --main-bg: #f0f2f5;
    --glass-border: rgba(255, 255, 255, 0.4);
    --card-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.07);
    --accent-soft: rgba(231, 76, 60, 0.1);
}

body {
    background: var(--main-bg);
    font-family: 'Inter', 'Hind Siliguri', sans-serif;
    margin: 0;
    display: flex;
    height: 100vh;
    overflow: hidden;
}

/* 1. Editable Sidebar (Navigation & Categories) */
aside.sidebar {
    width: 300px;
    background: var(--sidebar-bg);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border-right: 1px solid var(--glass-border);
    display: flex;
    flex-direction: column;
    z-index: 100;
}

.sidebar-header {
    padding: 25px;
    border-bottom: 1px solid rgba(0,0,0,0.05);
}

.brand-name {
    font-size: 22px;
    font-weight: 800;
    color: var(--primary);
    letter-spacing: -0.5px;
}

#searchBox {
    width: 100%;
    padding: 12px 15px;
    margin-top: 15px;
    border-radius: 12px;
    border: 1px solid rgba(0,0,0,0.05);
    background: #fff;
    box-sizing: border-box;
    outline: none;
    font-family: 'Hind Siliguri';
}

.nav-sections {
    flex: 1;
    overflow-y: auto;
    padding: 15px;
}

/* 2. Main Workspace */
main.workspace {
    flex: 1;
    display: flex;
    flex-direction: column;
    position: relative;
}

.top-ad-slot {
    height: 90px;
    background: #fff;
    margin: 10px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 1px dashed #cbd5e1;
}

.bento-container {
    flex: 1;
    padding: 20px;
    overflow-y: auto;
}

/* Bento Grid List Styles */
.category-group { margin-bottom: 30px; }
.category-title {
    font-family: 'Hind Siliguri';
    font-size: 18px;
    font-weight: 700;
    margin-bottom: 15px;
    color: #334155;
    display: flex;
    align-items: center;
    gap: 10px;
}
.category-title::before {
    content: ''; width: 4px; height: 18px; background: var(--primary); border-radius: 4px;
}

.grid-layout {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 15px;
}

.paper-card {
    background: #fff;
    border-radius: 16px;
    padding: 20px 10px;
    text-align: center;
    cursor: pointer;
    transition: 0.3s;
    border: 1px solid transparent;
    box-shadow: var(--card-shadow);
}

.paper-card:hover {
    transform: translateY(-5px);
    border-color: var(--primary);
    box-shadow: 0 12px 24px rgba(231, 76, 60, 0.15);
}

.paper-card img {
    width: 40px; height: 40px;
    object-fit: contain;
    margin-bottom: 10px;
    background: #f8fafc;
    border-radius: 10px;
    padding: 5px;
}

.paper-card span {
    display: block;
    font-size: 14px;
    font-weight: 600;
    font-family: 'Hind Siliguri';
    color: #1e293b;
}

/* 3. The Pro Viewer Modal */
#viewerOverlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0,0,0,0.8);
    z-index: 9999;
    display: none;
    backdrop-filter: blur(5px);
}

.viewer-content {
    width: 95%; height: 92%;
    background: #fff;
    margin: 2% auto;
    border-radius: 20px;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.viewer-toolbar {
    padding: 10px 20px;
    background: #fff;
    border-bottom: 1px solid #eee;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

#newsIframe { width: 100%; height: 100%; border: none; }

/* Responsive */
@media (max-width: 768px) {
    aside.sidebar { position: absolute; left: -300px; }
    .grid-layout { grid-template-columns: repeat(2, 1fr); }
}

body.script:
function openFrame(url, name) {
    document.getElementById('viewerTitle').innerText = name;
    document.getElementById('newsIframe').src = url;
    document.getElementById('viewerOverlay').style.display = 'block';
    document.body.style.overflow = 'hidden';
}

function closeFrame() {
    document.getElementById('viewerOverlay').style.display = 'none';
    document.getElementById('newsIframe').src = '';
    document.body.style.overflow = 'auto';
}

function filterList() {
    let q = document.getElementById('searchBox').value.toLowerCase();
    let cards = document.getElementsByClassName('paper-card');
    for (let c of cards) {
        let name = c.innerText.toLowerCase();
        c.style.display = name.includes(q) ? "block" : "none";
    }
}
